import os
import tarfile


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        dest_real = os.path.realpath(dest_path)
        os.makedirs(dest_real, exist_ok=True)
        if not os.path.isdir(dest_real):
            return False

        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                target = os.path.join(dest_real, member.name)
                real_target = os.path.realpath(target)

                if real_target != dest_real and not real_target.startswith(dest_real + os.sep):
                    return False

                if member.issym():
                    link_target = member.linkname
                    if os.path.isabs(link_target):
                        return False
                    link_abs = os.path.realpath(os.path.join(os.path.dirname(real_target), link_target))
                    if link_abs != dest_real and not link_abs.startswith(dest_real + os.sep):
                        return False
                    os.symlink(link_target, target)

                elif member.islnk():
                    return False

                elif member.isdir():
                    os.makedirs(target, exist_ok=True)

                elif member.isfile():
                    os.makedirs(os.path.dirname(target), exist_ok=True)
                    with open(target, 'wb') as out_file:
                        with tar.extractfile(member) as src_file:
                            if src_file is None:
                                return False
                            while True:
                                chunk = src_file.read(1024 * 1024)
                                if not chunk:
                                    break
                                out_file.write(chunk)

                else:
                    return False

        return True

    except Exception:
        return False

