from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        parser = etree.XMLParser(
            resolve_entities=False,
            no_network=True,
            load_dtd=False,
        )
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    students = root.xpath(
        "//student[username=$user and password=$pwd]",
        user=username,
        pwd=password,
    )

    if not students:
        return None

    student = students[0]
    return {child.tag: child.text or "" for child in student}

