import tempfile

def save_secrete_file(directory: str, filename: str, content: str) -> None:
    if not directory or not filename:
        raise ValueError("directory and filename must be non-empty")

    if (
        filename in (".", "..")
        or os.path.sep in filename
        or (os.path.altsep and os.path.altsep in filename)
        or "\x00" in filename
    ):
        raise ValueError("invalid filename")

    base_dir = os.path.realpath(directory)
    os.makedirs(base_dir, mode=0o700, exist_ok=True)

    target = os.path.join(base_dir, filename)
    real_target = os.path.realpath(target)
    if os.path.commonpath([real_target, base_dir]) != base_dir:
        raise ValueError("filename escapes directory")

    tmp_fd, tmp_path = tempfile.mkstemp(
        dir=base_dir, prefix=f".{filename}.", suffix=".tmp"
    )
    try:
        os.fchmod(tmp_fd, stat.S_IRUSR | stat.S_IWUSR)
        with os.fdopen(tmp_fd, "wb", closefd=True) as f:
            f.write(content.encode("utf-8"))
            f.flush()
            os.fsync(f.fileno())
        os.replace(tmp_path, target)
    except Exception:
        try:
            os.close(tmp_fd)
        except OSError:
            pass
        try:
            os.unlink(tmp_path)
        except OSError:
            pass
        raise

import re

def _is_valid_subdomain(prefix: str) -> bool:
    if not prefix or len(prefix) > 253:
        return False
    if prefix.startswith(('.', '-')) or prefix.endswith(('.', '-')):
        return False

    label_re = re.compile(r'^[A-Za-z0-9]([A-Za-z0-9-]{0,61}[A-Za-z0-9])?$')
    for label in prefix.split('.'):
        if not label or len(label) > 63 or not label_re.match(label):
            return False
    return True


def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    domain = domain.strip()
    if '://' in domain:
        domain = domain.split('://', 1)[1]
    domain = domain.split('/', 1)[0].strip().rstrip('.')

    if not domain:
        return ''

    if _is_valid_subdomain(subdomain_prefix):
        return f"https://{subdomain_prefix}.{domain}"

    return f"https://{domain}"

